const { exec } = require('child_process');
const { join } = require('path');
const fs = require('fs');

module.exports = async function (context, req) {
    const inputFileName = req.body.inputFileName;
    const outputFormat = req.body.outputFormat;
    const inputFilePath = join(__dirname, 'files', inputFileName);
    const outputFilePath = join(__dirname, 'files', `${inputFileName}.${outputFormat}`);

    if (!fs.existsSync(inputFilePath)) {
        context.res = {
            status: 400,
            body: "Input file does not exist."
        };
        return;
    }

    exec(`libreoffice --headless --convert-to ${outputFormat} "${inputFilePath}" --outdir "${join(__dirname, 'files')}"`, (error, stdout, stderr) => {
        if (error) {
            console.error(`Conversion error: ${error.message}`);
            context.res = {
                status: 500,
                body: `Error converting document: ${stderr}`
            };
            return;
        }

        context.res = {
            status: 200,
            body: `Document converted successfully. Output: ${outputFilePath}`
        };
    });
};